        long minSum = Long.MAX_VALUE;

        // Iterate over each element in the array
        for(int i=0; i<arr.length; i++) {
            // Temporary variable to store the current sum of absolute differences
            long tempSum = 0;

            // Compare the current element with every other element in the array
            for(int j=0; j<arr.length; j++) {
                if(i == j)
                    continue;

                // Add the absolute difference between the current pair of elements to tempSum
                tempSum += Math.abs(arr[i] - arr[j]);
            }

            // Update the minimum sum if the current tempSum is smaller
            minSum = Math.min(minSum, tempSum);
        }

        System.out.println(minSum); 
    }  
}
